using InventoryApp.Models;

namespace InventoryApp.Services;

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a database or API call
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new() { Id = 1, Name = "Hydraulic Press", Location = "Building A", LastInspected = new DateOnly(2026, 3, 15) },
            new() { Id = 2, Name = "CNC Lathe", Location = "Building B", LastInspected = new DateOnly(2026, 4, 22) },
            new() { Id = 3, Name = "Forklift #12", Location = "Warehouse", LastInspected = new DateOnly(2026, 5, 1) },
            new() { Id = 4, Name = "Conveyor Belt", Location = "Building A", LastInspected = new DateOnly(2026, 2, 10) },
            new() { Id = 5, Name = "Welding Robot", Location = "Building C", LastInspected = new DateOnly(2026, 5, 20) },
            new() { Id = 6, Name = "Air Compressor", Location = "Utility Room", LastInspected = new DateOnly(2026, 1, 8) },
            new() { Id = 7, Name = "Overhead Crane", Location = "Building B", LastInspected = new DateOnly(2025, 12, 30) },
            new() { Id = 8, Name = "Band Saw", Location = "Workshop", LastInspected = new DateOnly(2026, 4, 5) },
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@inject InventoryApp.Services.EquipmentService EquipmentService

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (Items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in Items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [PersistentState]
    public List<InventoryApp.Models.EquipmentItem>? Items { get; set; }

    protected override async Task OnInitializedAsync()
    {
        Items ??= await EquipmentService.GetEquipmentAsync();
    }
}

